300	/// Run the interactive web UI. Mirrors `Main.Mode.Interactive.run`:
301	/// builds a [`tamarin_server::ServerConfig`] from the CLI flags, eagerly
302	/// loads any positional `.spthy` files into the theory store, and serves
303	/// HTTP until SIGINT/SIGTERM. Returns 0 on graceful shutdown.
304	fn run_interactive(args: &Args) -> Result<i32, RunError> {
305	    use std::net::{IpAddr, Ipv4Addr, SocketAddr};
306	
307	    init_rayon_pool(args);
308	
309	    // Haskell defaults: 3001 on 127.0.0.1.
310	    let port = args.port.unwrap_or(DEFAULT_INTERACTIVE_PORT);
311	
312	    // `--interface` accepts a literal IP address. Haskell's `*4` / `*` /
313	    // `*6` magic strings bind to all interfaces; mirror those.
314	    let iface_str = args
315	        .interface
316	        .clone()
317	        .unwrap_or_else(|| "127.0.0.1".to_string());
318	    let ip: IpAddr = match iface_str.as_str() {
319	        "*" | "*4" => IpAddr::V4(Ipv4Addr::UNSPECIFIED),
320	        "*6" => IpAddr::V6(std::net::Ipv6Addr::UNSPECIFIED),
321	        other => other.parse::<IpAddr>().map_err(|e| {
322	            RunError(format!(
323	                "could not parse --interface={:?} as an IP address: {}\n\
324	                 Use --interface=\"*4\" to bind to all IPv4 interfaces.",
325	                other, e,
326	            ))
327	        })?,
328	    };
329	    let bind_addr = SocketAddr::new(ip, port);
330	
331	    // Resolve data dir. Without an explicit flag, look for `data/`
332	    // alongside the working directory or its ancestors — the same
333	    // search the server already exposes via `resolve_data_dir`.
334	    let data_dir = tamarin_server::handlers::static_files::resolve_data_dir(
335	        args.data_dir.clone().map(PathBuf::from),
336	    );
337	    // Try to discover a sibling frontend/dist for the bundled UI assets.
338	    let frontend_dist = guess_frontend_dist(&data_dir);
339	
340	    let maude_path = args.maude_path.clone().unwrap_or_else(default_maude_path);
341	
342	    let mut cfg = tamarin_server::ServerConfig::new(bind_addr, data_dir, maude_path);
343	    cfg.frontend_dist = frontend_dist;
344	    if let Some(b) = args.bound {
345	        cfg.max_steps = b as usize;
346	    }
347	    // `-d/--derivcheck-timeout` — same default expression as the batch
348	    // path's derivation-check block (default 5).
349	    cfg.derivcheck_timeout = args.derivcheck_timeout.unwrap_or(5) as u32;
350	    // CLI `--stop-on-trace` — merged with each theory's `configuration:`
351	    // block at load time (`ProofState::new`), HS `closeTheory` precedence.
352	    cfg.stop_on_trace = cli_cut(args);
353	
354	    // Positional args are theory files (Haskell uses a working
355	    // directory, but we accept either: a single dir arg, or one-or-more
356	    // .spthy paths).
357	    let theory_paths: Vec<PathBuf> = collect_theory_paths(&args.in_files)?;
358	
359	    if !args.quiet {
360	        // HS interactive runs the tool checks BEFORE the banner
361	        // (Interactive.hs:86-91): `ensureMaudeAndGetVersion` prints the
362	        // maude block (Console.hs:150-155) and `ensureGraphVizDot` the
363	        // GraphViz block (Environment.hs:72-87), both on stderr.
364	        {
365	            print_maude_banner(
366	                &maude_display_name(args),
367	                crate::cli::detect_maude_version_pub().as_deref(),
368	            );
369	            eprintln!("GraphViz tool: 'dot'");
370	            // HS lowercases `dot -V`'s stderr banner, strips the trailing
371	            // newline, and appends ". OK." (Environment.hs:81-87); PNG
372	            // support = "png" appears in the `dot -T?` error listing.
373	            if let Ok(out) = std::process::Command::new("dot").arg("-V").output() {
374	                let banner = String::from_utf8_lossy(&out.stderr).to_lowercase();
375	                if banner.contains("graphviz") {
376	                    eprintln!(" checking version: {}. OK.", banner.trim_end_matches('\n'));
377	                    let png_ok = std::process::Command::new("dot").arg("-T?").output()
378	                        .map(|o| {
379	                            let s = format!(
380	                                "{}{}",
381	                                String::from_utf8_lossy(&o.stdout),
382	                                String::from_utf8_lossy(&o.stderr),
383	                            );
384	                            s.to_lowercase().contains("png")
385	                        })
386	                        .unwrap_or(false);
387	                    if png_ok {
388	                        eprintln!(" checking PNG support: OK.");
389	                    }
390	                }
391	            }
392	        }
393	
394	        // HS startup banner (Interactive.hs:95-101) — stdout (`putStrLn`),
395	        // including the "Loading the security protocol theories" line and
396	        // the trailing blank line (`intercalate "\n" [.., ""]` plus
397	        // putStrLn's newline).  HS shows `workDir </> "*.spthy"`; we accept
398	        // dir-or-files, so a single dir arg renders HS-style and explicit
399	        // file paths are listed verbatim.
400	        let loading_what = match &args.in_files[..] {
401	            [one] if std::path::Path::new(one).is_dir() => {
402	                format!("{}", std::path::Path::new(one).join("*.spthy").display())
403	            }
404	            files => files.join(", "),
405	        };
406	        println!(
407	            "The server is starting up on port {}.\nBrowse to http://{} once the server is ready.\n\nLoading the security protocol theories '{}' ...\n",
408	            port, bind_addr, loading_what,
409	        );
410	    }
411	
412	    // Spin up a tokio runtime and run the server. We use a multi-thread
413	    // runtime so background `spawn_blocking` proof tasks don't park the
414	    // single executor thread.
415	    //
416	    // `thread_stack_size`: the web constraint-system pane is rendered as
417	    // ONE HughesPJ Doc (HS `prettyNonGraphSystem = vsep …`), and the
418	    // eager Doc builders (`beside`/`aboveNest`) recurse along the left
419	    // operand's token spine — depth scales with the pane size.  GHC grows
420	    // its stack on demand; tokio's default 2 MiB worker stacks do not, and
421	    // overflowed on fact-heavy panes (UM_three_pass).  64 MiB is reserved
422	    // virtual address space only (committed on use), applied to both
423	    // worker and `spawn_blocking` threads.
424	    let runtime = tokio::runtime::Builder::new_multi_thread()
425	        .enable_all()
426	        .thread_stack_size(64 * 1024 * 1024)
427	        .build()
428	        .map_err(|e| RunError(format!("failed to build tokio runtime: {}", e)))?;
429	    runtime
430	        .block_on(tamarin_server::serve(cfg, theory_paths))
431	        .map_err(|e| RunError(format!("server error: {}", e)))?;
432	    Ok(0)
433	}
