473	/// Resolve the effective cut strategy + auto-sources for one theory —
474	/// HS `closeTheory`'s configuration-block routing (TheoryLoader.hs:640-666).
475	///
476	/// The in-file `configuration: "…"` string accepts exactly two flags
477	/// (`theoryConfFlags`, TheoryLoader.hs:656-659): `--stop-on-trace[=v]`
478	/// (`flagOpt "dfs"` — valueless means `dfs`) and `--auto-sources`
479	/// (`flagNone`).  Precedence: the CLI `--stop-on-trace` wins when given
480	/// (`configStopOnTrace` consults the block only when the CLI flag is
481	/// absent); `--auto-sources` is OR-combined (`configAutoSources`).  Bare
482	/// (non-flag) tokens land in cmdargs' positional catch-all
483	/// (`flagArg (updateArg "") ""`) and are ignored; an unknown flag or
484	/// stop-on-trace value aborts the run (cmdargs `processValue` /
485	/// `error e` on `ArgumentError`, TheoryLoader.hs:661).
486	///
487	/// The strategy only steers prove-mode (`constructAutoProver` is used
488	/// solely when `thyOpts.proveMode`, TheoryLoader.hs:606); without
489	/// `--prove` the non-prove default `CutDFS` applies.
490	fn effective_config(
491	    args: &Args,
492	    parsed: &tamarin_parser::ast::Theory,
493	) -> Result<(tamarin_theory::constraint::solver::context::CutStrategy, bool), RunError> {
494	    use tamarin_theory::constraint::solver::context::CutStrategy;
495	    let (block_cut, block_auto_sources) = match &parsed.configuration {
496	        Some(cfg) => tamarin_theory::prove::config_block_options(cfg)
497	            .map_err(RunError)?,
498	        None => (None, false),
499	    };
500	    let cut = if args.prove_mode {
501	        match &args.stop_on_trace {
502	            Some(s) => stop_on_trace_cut(s),
503	            None => block_cut.unwrap_or(CutStrategy::Dfs),
504	        }
505	    } else {
506	        CutStrategy::Dfs
507	    };
508	    Ok((cut, args.auto_sources || block_auto_sources))
509	}
