511	/// Map a CLI `--stop-on-trace` value to its `CutStrategy`.  Shared by
512	/// `effective_config` (batch prove-mode) and `cli_cut` (interactive), so the
513	/// two cannot drift.
514	fn stop_on_trace_cut(
515	    s: &crate::cli::StopOnTrace,
516	) -> tamarin_theory::constraint::solver::context::CutStrategy {
517	    use tamarin_theory::constraint::solver::context::CutStrategy;
518	    match s {
519	        crate::cli::StopOnTrace::Dfs => CutStrategy::Dfs,
520	        crate::cli::StopOnTrace::SeqDfs => CutStrategy::SeqDfs,
521	        crate::cli::StopOnTrace::Bfs => CutStrategy::Bfs,
522	        crate::cli::StopOnTrace::Sorry => CutStrategy::AfterSorry,
523	        crate::cli::StopOnTrace::None => CutStrategy::Nothing,
524	    }
525	}
