777	        // Formula guardedness (HS `formulaReports`).  The parser-level
778	        // `check_theory` already emitted this bundle, but with an EMPTY
779	        // reducible-symbol set (it runs pre-elaboration, with no signature).
780	        // Re-run it now with the reducible funsym names derived from the
781	        // elaborated `MaudeSig` so the Formula-terms check classifies reducible
782	        // symbols against the real signature.  Strip the empty-reducible bundle
783	        // first, then splice the reducible-aware one at the formulaReports
784	        // position (before Lemma annotations).
785	        {
786	            let reducible =
787	                tamarin_theory::wf_adapt::reducible_funsym_names(&maude_sig);
