851	            // `_sapic_funs_guard` so the generated lemmas' embedded case-test
852	            // formulas resolve their user function symbols with the theory's
853	            // private/destructor flags.
854	            if let Err(e) = tamarin_accountability::translate(&mut parsed, &mut elaborated) {
