1544	fn default_maude_path() -> String {
1545	    for c in [
1546	        "/usr/local/bin/maude",
1547	        "/usr/bin/maude",
1548	    ] {
1549	        if std::path::Path::new(c).exists() {
1550	            return c.to_string();
1551	        }
1552	    }
1553	    "maude".to_string()
1554	}
