1606	fn print_overall_summary(file_results: &[FileResult], prove_mode: bool) {
1607	    // Mirrors HS `summary of summaries:` block (`Main.Mode.Batch`).
1608	    let line = "=".repeat(78);
1609	    println!();
1610	    println!("{}", line);
1611	    println!("summary of summaries:");
1612	    println!();
1613	    for fr in file_results {
1614	        println!("analyzed: {}", fr.in_file);
1615	        // HS `ppRep` (Batch.hs:146-148) has TWO `Pretty.text ""` between
1616	        // `analyzed:` and the nested `output:`/`processing time:` block, but
1617	        // HughesPJ collapses adjacent empty lines under `vcat`, so the rendered
1618	        // output is a SINGLE blank line here.  Verified against the v1.13.0
1619	        // binary: `tamarin-prover --prove` emits exactly one blank line between
1620	        // `analyzed:` and `output:`/`processing time:`, so one `println!()` is
1621	        // byte-faithful.
1622	        println!();
1623	        if let Some(out) = &fr.out_file {
1624	            // HS aligns `output:` and `processing time:` columns
1625	            // (`ppRep` in Main.Mode.Batch, src/Main/Mode/Batch.hs:144).
1626	            println!("  output:          {}", out);
1627	        }
1628	        println!("  processing time: {:.2}s", fr.elapsed_ms as f64 / 1000.0);
1629	        println!("  ");
1630	        if fr.wf_count > 0 {
1631	            println!("  WARNING: {} wellformedness check failed!", fr.wf_count);
1632	            // HS Batch.hs:246 emits this second line only in prove mode:
1633	            //   [ Pretty.text "         The analysis results might be wrong!"
1634	            //   | thyLoadOptions.proveMode ]
1635	            if prove_mode {
1636	                println!("           The analysis results might be wrong!");
1637	            }
1638	            // HS `summary = ppWf report $--$ prettyClosedSummary` (Batch.hs:228-229):
1639	            // `$--$` (above with a blank-line gap) inserts the blank ONLY when
1640	            // both operands are non-empty.  Under the enclosing `nest 2` a
1641	            // blank `Pretty.text ""` renders as `"  "`.  So this separator
1642	            // appears between the warning block and the per-lemma summary
1643	            // lines ONLY when there are summary lines to follow; emitting it
1644	            // unconditionally would add a spurious trailing `"  "` line.
1645	            if !fr.results.is_empty() {
1646	                println!("  ");
1647	            }
1648	        }
1649	        for r in &fr.results {
1650	            println!("  {}", format_lemma_summary_line(r));
1651	        }
1652	        println!();
1653	    }
1654	    println!("{}", line);
1655	}
