1	//! Workspace adapter routing this crate's `--help` / `--version` rendering
2	//! through the vendored clean-room console text modules (`super::help`,
3	//! `super::version`, `super::modes`). This file is pure type conversion and
4	//! data plumbing: it maps the ported [`super::Subcommand`] to the clean
5	//! [`Mode`] and fills the clean [`VersionInfo`] slots from this binary's own
6	//! build metadata (`super::VERSION` / `GIT_REV` / `GIT_BRANCH` /
7	//! `BUILD_TIMESTAMP`) and the detected Maude version. No render logic lives
8	//! here — the byte-exact HS text comes entirely from the clean modules.
9	
10	use super::help::render_help;
11	use super::modes::Mode;
12	use super::stream::Streams;
13	use super::version::{frame_version, MaudeInfo, VersionInfo};
14	use super::Subcommand;
15	
16	/// Map the ported subcommand to the clean text-surface mode.
17	fn mode_of(sub: &Subcommand) -> Mode {
18	    match sub {
19	        Subcommand::Batch => Mode::Batch,
20	        Subcommand::Interactive => Mode::Interactive,
21	        Subcommand::Variants => Mode::Variants,
22	        Subcommand::Test => Mode::Test,
23	    }
24	}
25	
26	/// The byte-exact HS help page for the active subcommand.
27	pub fn help_text(sub: &Subcommand) -> &'static str {
28	    render_help(mode_of(sub))
29	}
30	
31	/// The default (batch) help page — for callers with no subcommand in scope
32	/// (parse-error fallback, batch "no input files" envelope).
33	pub fn help_text_default() -> &'static str {
34	    render_help(Mode::Batch)
35	}
