37	/// The full `--version`/`-V` output across both standard streams, byte-exact
38	/// against the HS split-stream captures (`split_version.out.txt` /
39	/// `split_version.err.txt`) with this binary's build metadata in the slots.
40	///
41	/// The round-4 clean version model split what the merged (`2>&1`) oracle
42	/// interleaved: the banner (tamarin line + warranty + `Generated from:` block)
43	/// is stdout; the 3-line maude readiness preamble is stderr. `frame_version`
44	/// assembles both from one [`VersionInfo`].
45	pub fn version_streams() -> Streams {
46	    let maude_version =
47	        super::detect_maude_version_pub().unwrap_or_else(|| "unknown version".to_string());
48	    let info = VersionInfo {
49	        maude: MaudeInfo { path: "maude".to_string(), version: maude_version },
50	        tamarin_version: super::VERSION.to_string(),
51	        copyright_years: "2010-2023".to_string(),
52	        git_description: format!("{}, branch: {}", super::GIT_REV, super::GIT_BRANCH),
53	        compiled_at: super::BUILD_TIMESTAMP.to_string(),
54	    };
55	    frame_version(&info)
56	}
