217	    /// `--processors=N` — size of the rayon worker pool used for
218	    /// HS-faithful internal parallelism (rule-variant closure,
219	    /// per-source saturate change-detection, per-item pretty-print).
220	    /// `None` = use default (`available_parallelism()` — full machine).
221	    /// `Some(1)` = single-threaded, byte-identical to sequential output.
222	    /// Mirrors HS's `+RTS -N RTS_FLAG` in spirit — see
223	    /// `lib/theory/src/Prover.hs:102,195`, `Theory/Constraint/Solver/Sources.hs:362`,
224	    /// `lib/theory/src/TheoryObject.hs:744,752`.
225	    pub processors: Option<usize>,
