1	//! `parse(argv) -> Result<Command, CliError>`.
2	//!
3	//! Turns an argument vector into a structured [`Command`] or ready-to-print
4	//! error text. Parsing is pure (no filesystem access): the two cmdargs-level
5	//! errors that require the filesystem — the interactive WORKDIR existence check —
6	//! are surfaced as a [`RunSpec`] the caller can validate with
7	//! [`crate::errors::directory_does_not_exist`]. The "no input files given" check
8	//! needs no filesystem and is emitted here.
9	
10	use crate::errors::{self, CliError};
11	use crate::modes::{flags_for, FlagSpec, Mode};
12	
13	/// A structured, actionable command produced by [`parse`].
14	#[derive(Debug, Clone, PartialEq, Eq)]
15	pub enum Command {
16	    /// Print the given mode's help page (exit 0).
17	    Help(Mode),
18	    /// Print the version banner (exit 0). Only reachable in the default mode.
19	    Version,
20	    /// A mode invocation with parsed positionals and options.
21	    Run(RunSpec),
22	}
23	
24	/// A parsed mode invocation.
25	#[derive(Debug, Clone, PartialEq, Eq)]
26	pub struct RunSpec {
27	    pub mode: Mode,
28	    /// FILES (batch/test) or the WORKDIR token(s) (interactive).
29	    pub positional: Vec<String>,
30	    pub options: Options,
31	}
32	
33	/// Recognized flags recorded in encounter order.
34	#[derive(Debug, Clone, Default, PartialEq, Eq)]
35	pub struct Options {
36	    /// `(canonical_long_name, value)` per occurrence; `value` is `None` for the
37	    /// bare form of a value flag and for boolean flags.
38	    pub flags: Vec<(String, Option<String>)>,
39	}
40	
41	impl Options {
42	    /// True if the boolean/valued flag with this canonical long name was seen.
43	    pub fn is_set(&self, long: &str) -> bool {
44	        self.flags.iter().any(|(n, _)| n == long)
45	    }
46	    /// All values supplied for a (possibly repeated) flag.
47	    pub fn values(&self, long: &str) -> Vec<&str> {
48	        self.flags
49	            .iter()
50	            .filter(|(n, _)| n == long)
51	            .filter_map(|(_, v)| v.as_deref())
52	            .collect()
53	    }
54	    /// The last occurrence of a flag (last-wins semantics): `None` if the flag is
55	    /// absent, `Some(None)` if its last occurrence was bare, `Some(Some(v))` if
56	    /// its last occurrence carried the value `v`.
57	    pub fn last(&self, long: &str) -> Option<Option<&str>> {
58	        self.flags
59	            .iter()
60	            .rev()
61	            .find(|(n, _)| n == long)
62	            .map(|(_, v)| v.as_deref())
63	    }
64	    /// Every occurrence of a repeatable flag, in order; each element is `None` for
65	    /// a bare occurrence or `Some(v)` for a valued one.
66	    pub fn occurrences(&self, long: &str) -> Vec<Option<String>> {
67	        self.flags
68	            .iter()
69	            .filter(|(n, _)| n == long)
70	            .map(|(_, v)| v.clone())
71	            .collect()
72	    }
73	}
74	
75	/// Parse an argument vector (excluding argv[0]/program name).
76	pub fn parse(argv: &[String]) -> Result<Command, CliError> {
77	    // 1. Determine mode and the slice of tokens to parse within it.
78	    let (mode, rest): (Mode, &[String]) = match argv.first() {
79	        // Truly empty argv is not observable through the oracle; treated as the
80	        // default-mode no-input case (documented inference).
81	        None => return Err(errors::no_input_files(Mode::Batch)),
82	        Some(first) if first.starts_with('-') => (Mode::Batch, argv),
83	        Some(first) => {
84	            let matches = Mode::prefix_matches(first);
85	            match matches.len() {
86	                1 => (matches[0].1, &argv[1..]),
87	                0 => (Mode::Batch, argv), // not a mode prefix -> a FILE
88	                _ => {
89	                    let names: Vec<&str> = matches.iter().map(|(n, _)| *n).collect();
90	                    return Err(errors::ambiguous_mode(first, &names));
91	                }
92	            }
93	        }
94	    };
95	
96	    // 2. Left-to-right token scan within the chosen mode.
97	    let table = flags_for(mode);
98	    let mut options = Options::default();
99	    let mut positional: Vec<String> = Vec::new();
100	
101	    let mut i = 0;
102	    while i < rest.len() {
103	        let tok = &rest[i];
104	        if let Some(body) = tok.strip_prefix("--") {
105	            // Long flag: `--name` or `--name=value`.
106	            let (name, mut value) = match body.split_once('=') {
107	                Some((n, v)) => (n, Some(v.to_string())),
108	                None => (body, None),
109	            };
110	            let spec = lookup_long(&table, name)
111	                .ok_or_else(|| errors::unknown_flag(&format!("--{name}")))?;
112	            if !spec.takes_value && value.is_some() {
113	                return Err(errors::unhandled_argument(tok));
114	            }
115	            // A consumer-extension flag with no attached value takes the following
116	            // token as its value (the `--flag <value>` surface).
117	            if spec.consumes_next && value.is_none() {
118	                if let Some(next) = rest.get(i + 1) {
119	                    value = Some(next.clone());
120	                    i += 1;
121	                } else {
122	                    return Err(errors::missing_value(&format!("--{name}")));
123	                }
124	            }
125	            if let Some(c) = short_circuit(spec.long, mode) {
126	                return Ok(c);
127	            }
128	            options.flags.push((spec.long.to_string(), value));
129	        } else if tok.len() >= 2 && tok.starts_with('-') && tok != "--" {
130	            // Short flag: `-x` or `-x<attached value>`.
131	            let mut chars = tok[1..].chars();
132	            let c = chars.next().unwrap();
133	            let attached: String = chars.collect();
134	            let spec = lookup_short(&table, c)
135	                .ok_or_else(|| errors::unknown_flag(tok))?;
136	            if spec.takes_value {
137	                let value = if attached.is_empty() { None } else { Some(attached) };
138	                if let Some(cmd) = short_circuit(spec.long, mode) {
139	                    return Ok(cmd);
140	                }
141	                options.flags.push((spec.long.to_string(), value));
142	            } else {
143	                // Boolean short flag: only the bare form is recognized here.
144	                if !attached.is_empty() {
145	                    return Err(errors::unknown_flag(tok));
146	                }
147	                if let Some(cmd) = short_circuit(spec.long, mode) {
148	                    return Ok(cmd);
149	                }
150	                options.flags.push((spec.long.to_string(), None));
151	            }
152	        } else {
153	            // Positional token (a FILE, or the WORKDIR for interactive).
154	            positional.push(tok.clone());
155	        }
156	        i += 1;
157	    }
158	
159	    // 3. Positional-arity validation that cmdargs performs at parse time.
160	    // Batch and test require at least one input FILE.
161	    if matches!(mode, Mode::Batch | Mode::Test) && positional.is_empty() {
162	        return Err(errors::no_input_files(mode));
163	    }
164	
165	    Ok(Command::Run(RunSpec { mode, positional, options }))
166	}
167	
168	/// Map an About flag to its terminal command, if it is one.
169	fn short_circuit(long: &str, mode: Mode) -> Option<Command> {
170	    match long {
171	        "help" => Some(Command::Help(mode)),
172	        "version" => Some(Command::Version),
173	        _ => None,
174	    }
175	}
176	
177	fn lookup_long<'a>(table: &'a [FlagSpec], name: &str) -> Option<&'a FlagSpec> {
178	    table
179	        .iter()
180	        .find(|f| f.long == name || f.aliases.contains(&name))
181	}
182	
183	fn lookup_short(table: &[FlagSpec], c: char) -> Option<&FlagSpec> {
184	    table.iter().find(|f| f.short == Some(c))
185	}
