1	//! Incremental (streaming) emission of the batch output.
2	//!
3	//! The assembled model in [`crate::framing`] builds both complete [`Streams`]
4	//! and hands them back at the end. A consumer that wants output to appear *as
5	//! the prover runs* — progress markers and payloads flushed while later theories
6	//! are still being processed — needs to drive emission event-by-event instead.
7	//!
8	//! This module provides that drive surface. A [`Sink`] is the consumer's byte
9	//! destination, tagged by [`Stream`]; the consumer decides when (or whether) to
10	//! flush after each call. [`BatchEmitter`] defines *what* bytes are produced and
11	//! *in what per-stream order* — nothing here forces buffering or a final barrier
12	//! except the "summary of summaries" block, which is inherently a single trailing
13	//! block over every theory and so is buffered until [`BatchEmitter::finish`].
14	//!
15	//! The per-stream byte total is identical to the assembled model: both paths
16	//! emit, on stderr, the maude preamble then each theory's progress in order, and,
17	//! on stdout, each printed payload in order then the one combined summary. The two
18	//! streams interleave differently in wall-clock time (that is the point of
19	//! streaming), but each stream's byte sequence is unchanged. The equivalence is
20	//! exercised by the crate's tests via [`drive_batch`].
21	
22	use crate::framing::{progress_line, render_summary, BatchTheory, Phase, Summary, CLOSED_PHASES};
23	use crate::stream::{Stream, Streams};
24	use crate::version::{maude_preamble, MaudeInfo};
25	
26	/// A byte destination the incremental emitter writes to, tagged by which standard
27	/// stream the bytes belong on. Implementors choose flush timing: a
28	/// flush-per-call sink yields true line-by-line streaming; a buffering sink
29	/// coalesces. The emitter never assumes either.
30	pub trait Sink {
31	    /// Hand `text` to the destination for `stream`. Called once per emitted chunk
32	    /// in emission order.
33	    fn emit(&mut self, stream: Stream, text: &str);
34	}
35	
36	/// A [`Sink`] that accumulates into an in-memory [`Streams`]. Useful for tests
37	/// and for callers that want the fully assembled result from the streaming path.
38	#[derive(Debug, Clone, Default)]
39	pub struct StreamCollector {
40	    pub streams: Streams,
41	}
42	
43	impl Sink for StreamCollector {
44	    fn emit(&mut self, stream: Stream, text: &str) {
45	        self.streams.push(stream, text);
46	    }
47	}
48	
49	/// Drives incremental emission of a closed batch run into a [`Sink`].
50	///
51	/// Lifecycle: [`begin`](Self::begin) emits the preamble; then, per theory as the
52	/// engine produces it, call [`progress`](Self::progress) for each phase reached,
53	/// [`extra_progress`](Self::extra_progress) for any engine lines after the last
54	/// phase, [`payload`](Self::payload) when the theory's pretty-print is ready, and
55	/// [`record_summary`](Self::record_summary) once its verdict is known; finally
56	/// [`finish`](Self::finish) emits the combined summary. The consumer may flush its
57	/// sink at any point between calls.
58	pub struct BatchEmitter<'a, S: Sink> {
59	    sink: &'a mut S,
60	    summaries: Vec<Summary>,
61	}
62	
63	impl<'a, S: Sink> BatchEmitter<'a, S> {
64	    /// Start a batch run: emit the three-line maude readiness preamble on stderr.
65	    pub fn begin(sink: &'a mut S, maude: &MaudeInfo) -> Self {
66	        sink.emit(Stream::Err, &maude_preamble(maude));
67	        BatchEmitter { sink, summaries: Vec::new() }
68	    }
69	
70	    /// Emit one `[Theory <name>] <phase>` progress marker on stderr.
71	    pub fn progress(&mut self, theory: &str, phase: Phase) {
72	        self.sink.emit(Stream::Err, &progress_line(theory, phase));
73	    }
74	
75	    /// Emit all five closed-theory progress markers for `theory`, in order.
76	    pub fn closed_phases(&mut self, theory: &str) {
77	        for phase in CLOSED_PHASES {
78	            self.progress(theory, phase);
79	        }
80	    }
81	
82	    /// Emit further engine progress lines on stderr, verbatim (already
83	    /// newline-terminated), e.g. the `[Saturating Sources] …` lines a `--prove`
84	    /// run appends after a theory's `Theory closed` marker. A no-op for `""`.
85	    pub fn extra_progress(&mut self, text: &str) {
86	        if !text.is_empty() {
87	            self.sink.emit(Stream::Err, text);
88	        }
89	    }
90	
91	    /// Emit a theory's pretty-printed payload on stdout. Pass `None` when the
92	    /// theory was written to an output file instead (nothing is emitted).
93	    pub fn payload(&mut self, payload: Option<&str>) {
94	        if let Some(p) = payload {
95	            self.sink.emit(Stream::Out, p);
96	        }
97	    }
98	
99	    /// Record this theory's contribution to the trailing summary. Buffered until
100	    /// [`finish`](Self::finish), because the "summary of summaries" is one block
101	    /// over every theory.
102	    pub fn record_summary(&mut self, summary: Summary) {
103	        self.summaries.push(summary);
104	    }
105	
106	    /// Emit the combined "summary of summaries" block on stdout, closing the run.
107	    pub fn finish(self) {
108	        self.sink.emit(Stream::Out, &render_summary(&self.summaries));
109	    }
110	}
111	
112	/// Convenience driver: stream a whole `&[BatchTheory]` into `sink` in the natural
113	/// per-theory order (preamble; then, per theory, its closed phases, extra
114	/// progress, payload, and recorded summary; then the combined summary). Produces
115	/// per-stream bytes identical to [`crate::framing::frame_batch`] on the same
116	/// inputs — the streaming/assembled equivalence the interop requirement asks for.
117	pub fn drive_batch<S: Sink>(sink: &mut S, maude: &MaudeInfo, theories: &[BatchTheory]) {
118	    let mut e = BatchEmitter::begin(sink, maude);
119	    for t in theories {
120	        e.closed_phases(&t.name);
121	        e.extra_progress(&t.extra_progress);
122	        e.payload(t.payload.as_deref());
123	        e.record_summary(t.summary.clone());
124	    }
125	    e.finish();
126	}
